/**
 * File upload API endpoints for sessions.
 *
 * Routes:
 * - POST /api/session/:token/files - Upload a PDF file
 * - GET /api/session/:token/files - List uploaded files
 * - DELETE /api/session/:token/files/:filename - Delete a file
 *
 * File operations are allowed in patient_joined and data_submitted statuses.
 */

import { SESSION_OPERATION_RULES } from "../../../lib/domain/constants";
import { badRequest, jsonResponse, notFound, serverError } from "../../../lib/http-responses";
import { logger } from "../../../lib/logging/logger";
import { deleteFile, listFiles, saveFile } from "../../../lib/session/files";
import { validatePublicSession } from "../../../lib/session/validation";
import { extractRouteParam } from "../../../lib/utils";

// TODO(unit): replaced local validateSession with shared validateSessionForOperation, needs unit test coverage for expiry behavior

/**
 * POST /api/session/:token/files
 * Upload a PDF file to a session
 */
// TODO(unit): replaced inline extractTokenFromPath with extractRouteParam utility, needs unit test coverage
export async function POST(req: Request): Promise<Response> {
	try {
		// URL format: /api/session/{token}/files
		const token = extractRouteParam(req, "token", -2);

		const validation = await validatePublicSession(token, {
			checkExpiry: true,
			allowedStatuses: SESSION_OPERATION_RULES.FILE_OPERATIONS,
		});
		if (!validation.valid) {
			return validation.response;
		}

		// Parse form data
		const formData = await req.formData();
		const file = formData.get("file") as File | null;

		if (!file) {
			return badRequest("No file provided");
		}

		logger.info("Session file upload request received", {
			sessionTokenPrefix: token.slice(0, 8),
			filename: file.name,
			mimeType: file.type || "unknown",
			size: file.size,
		});

		// Save file
		const metadata = await saveFile(token, file);

		logger.info("Session file upload completed", {
			sessionTokenPrefix: token.slice(0, 8),
			filename: metadata.filename,
			size: metadata.size,
		});

		return jsonResponse(
			{
				success: true,
				file: metadata,
			},
			201,
		);
	} catch (error) {
		logger.error("Session file upload failed", {
			error: String(error),
		});

		if (error instanceof Error && error.message.includes("Only PDF")) {
			return badRequest(error.message);
		}

		return serverError();
	}
}

/**
 * GET /api/session/:token/files
 * List all files uploaded to a session
 */
export async function GET(req: Request): Promise<Response> {
	try {
		// URL format: /api/session/{token}/files
		const token = extractRouteParam(req, "token", -2);

		const validation = await validatePublicSession(token, {
			checkExpiry: true,
			allowedStatuses: SESSION_OPERATION_RULES.FILE_OPERATIONS,
		});
		if (!validation.valid) {
			return validation.response;
		}

		const files = await listFiles(token);

		return jsonResponse({
			files,
		});
	} catch (error) {
		console.error("Error listing files:", error);
		return serverError();
	}
}

/**
 * DELETE /api/session/:token/files/:filename
 * Delete a file from a session
 */
export async function DELETE(req: Request): Promise<Response> {
	try {
		// URL format: /api/session/{token}/files/{filename}
		// pathParts: ["api", "session", "{token}", "files", "{filename}"]
		// token at index 2 (-3), filename at index 4 (-1)
		const token = extractRouteParam(req, "token", -3);
		const filename = extractRouteParam(req, "filename", -1);

		const validation = await validatePublicSession(token, {
			checkExpiry: true,
			allowedStatuses: SESSION_OPERATION_RULES.FILE_OPERATIONS,
		});
		if (!validation.valid) {
			return validation.response;
		}

		if (!filename) {
			return badRequest("No filename provided");
		}

		const deleted = await deleteFile(token, filename);

		if (!deleted) {
			return notFound("File");
		}

		return jsonResponse({
			success: true,
			message: "File deleted",
		});
	} catch (error) {
		console.error("Error deleting file:", error);
		return serverError();
	}
}

