import { type ClassValue, clsx } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
	return twMerge(clsx(inputs));
}

/**
 * Extract a route parameter from the URL pathname.
 * Handles parameterized routes like /api/resource/:id where Bun.serve
 * doesn't automatically provide params object.
 *
 * @param req - The Request object
 * @param paramName - The name of the parameter (e.g., "token", "id")
 * @param segmentIndex - The index of the path segment containing the param (default: -1 for last segment)
 * @returns The extracted parameter value or null if not found
 *
 * @example
 * // For route "/api/invite/:token/validate"
 * const token = extractRouteParam(req, "token", -2); // Gets second-to-last segment
 *
 * // For route "/api/sessions/:id"
 * const id = extractRouteParam(req, "id"); // Gets last segment by default
 */
export function extractRouteParam(
	req: Request,
	_paramName: string,
	segmentIndex: number = -1,
): string | null {
	try {
		const url = new URL(req.url);
		const pathParts = url.pathname.split("/").filter(Boolean); // Remove empty strings

		const index = segmentIndex < 0 ? pathParts.length + segmentIndex : segmentIndex;

		if (index >= 0 && index < pathParts.length) {
			return pathParts[index] ?? null;
		}

		return null;
	} catch {
		return null;
	}
}

