/**
 * Extract guidance type from URL path
 * Pattern: /api/admin/guidance-center/defaults/:type
 */
function extractTypeFromUrl(url: string): string | null {
	const parts = url.split("/");
	// /api/admin/guidance-center/defaults/:type
	//  0   1     2                 3         4
	const typeIndex = parts.indexOf("defaults") + 1;
	return parts[typeIndex] || null;
}

/**
