 * Helper to check if verbose logging is enabled
 * Useful for conditional expensive operations
 */
export function isVerboseLogging(): boolean {
	return logger.levels[logger.level] >= logger.levels.verbose;
}

/**
 * Helper to create a timer for verbose logging
 * Returns a function that logs the elapsed time when called
 */
export function createVerboseTimer(label: string, meta?: Record<string, unknown>) {
	const start = performance.now();
	return () => {
		const elapsed = performance.now() - start;
		logger.verbose(`${label} completed`, { ...meta, elapsedMs: elapsed.toFixed(2) });
	};
}

